#!/bin/bash\n\nSUBDOMAIN=\"$1\"\nDEPLOYMENTS_FILE=\"/data/.openclaw/workspace/publish-website-traefik/deployments.json\"\n\nif [ -z \"$SUBDOMAIN\" ]; then\n    echo \"Usage: ./scripts/delete_site.sh <subdomain>\"\n    exit 1\nfi\n\nif [ ! -f \"$DEPLOYMENTS_FILE\" ]; then\n    echo \"No deployments file found. Nothing to delete.\"\n    exit 0\nfi\n\n# Get deployment details\nDEPLOYMENT_INFO=$(jq -r --arg subdomain \"$SUBDOMAIN\" '.[$subdomain]' \"$DEPLOYMENTS_FILE\")\n\nif [ \"$DEPLOYMENT_INFO\" == \"null\" ]; then\n    echo \"Deployment for subdomain '$SUBDOMAIN' not found.\"\n    exit 1\nfi\n\nTEMP_DIR=$(echo \"$DEPLOYMENT_INFO\" | jq -r '.temp_dir')\n\necho \"Deleting deployment for $SUBDOMAIN...\"\n\n# Navigate to temp_dir and bring down docker compose\nif [ -d \"$TEMP_DIR\" ]; then\n    echo \"Changing to $TEMP_DIR to bring down services.\"\n    pushd \"$TEMP_DIR\" || { echo \"Failed to change directory to $TEMP_DIR\"; exit 1; }\n    docker compose down -v || { echo \"Failed to bring down docker compose services\"; popd; exit 1; }\n    popd\n    echo \"Services for $SUBDOMAIN brought down.\"\n    rm -rf \"$TEMP_DIR\"\n    echo \"Temporary directory $TEMP_DIR removed.\"\nelse\n    echo \"Warning: Temporary directory $TEMP_DIR not found, assuming services are already down.\"\nfi\n\n# Remove entry from deployments.json\njq --arg subdomain \"$SUBDOMAIN\" 'del(.[$subdomain])' \"$DEPLOYMENTS_FILE\" > \"${DEPLOYMENTS_FILE}.tmp\" && mv \"${DEPLOYMENTS_FILE}.tmp\" \"$DEPLOYMENTS_FILE\"\necho \"Deployment entry for $SUBDOMAIN removed from $DEPLOYMENTS_FILE.\"\n\necho \"Deployment for $SUBDOMAIN successfully deleted.\"\n